import { registerList, ListNode, ListItemNode, registerListStrictIndentTransform } from '@lexical/list';
import { useLexicalComposerContext } from '@lexical/react/LexicalComposerContext';
import { mergeRegister } from 'lexical';
import { useEffect } from 'react';

/**
 * Copyright (c) Meta Platforms, Inc. and affiliates.
 *
 * This source code is licensed under the MIT license found in the
 * LICENSE file in the root directory of this source tree.
 *
 */

function useList(editor) {
  useEffect(() => {
    return registerList(editor);
  }, [editor]);
}

/**
 * Copyright (c) Meta Platforms, Inc. and affiliates.
 *
 * This source code is licensed under the MIT license found in the
 * LICENSE file in the root directory of this source tree.
 *
 */

function ListPlugin({
  hasStrictIndent = false,
  shouldPreserveNumbering = false
}) {
  const [editor] = useLexicalComposerContext();
  useEffect(() => {
    if (!editor.hasNodes([ListNode, ListItemNode])) {
      throw new Error('ListPlugin: ListNode and/or ListItemNode not registered on editor');
    }
  }, [editor]);
  useEffect(() => {
    return mergeRegister(registerList(editor, {
      restoreNumbering: shouldPreserveNumbering
    }), hasStrictIndent ? registerListStrictIndentTransform(editor) : () => {});
  }, [editor, hasStrictIndent, shouldPreserveNumbering]);
  useList(editor);
  return null;
}

export { ListPlugin };
